sql:
SELECT segment_id, trail_id, segment_name, description, distance, cumulative_distance, elevation_change, image_url, start_coordinates, end_coordinates, estimated_time, trail_conditions, trail_type
FROM trail_segments
WHERE cumulative_distance > 500;

SELECT SUM(total_distance) AS total_distance_travelled
FROM hikes
WHERE user_id = 1;

SELECT trail_id, COUNT(*) as num_reviews
FROM trail_reviews
GROUP BY trail_id;

SELECT COUNT(segment_id) AS segment_count
FROM trail_segments
WHERE ABS(
    CAST(SUBSTR(start_coordinates, 1, INSTR(start_coordinates, ',') - 1) AS REAL) - 
    CAST(SUBSTR(start_coordinates, INSTR(start_coordinates, ',') + 2) AS REAL)
) <= 10;

SELECT review_id, review_text
FROM trail_reviews
ORDER BY helpful_count DESC;

SELECT r.region_name, t.trail_name
FROM regions r
JOIN trails t ON r.region_id = t.region_id;

SELECT total_distance
FROM hikes
WHERE user_id = 1;

external_knowledge:
- 'first region' refers to the region with region_id = 1;
- 'path' is synonymous with 'trail';
- 'hike lengths' indicates the total distances of hikes, which are averaged for each trail.

sql:
SELECT hike_id, segment_id 
FROM hike_segments
WHERE distance_covered > 0.5;

SELECT DISTINCT users.user_name
FROM users
JOIN trail_reviews ON users.user_id = trail_reviews.user_id;

SELECT trail_name, difficulty
FROM trails
WHERE trail_id = 1;

SELECT AVG(rating) AS average_rating
FROM trail_reviews
WHERE strftime('%m', review_date) = '<month>';
